import { Component, OnInit } from '@angular/core';
import { CommonModule } from '@angular/common';
import { FormBuilder, FormGroup, ReactiveFormsModule, Validators } from '@angular/forms';
import { ActivatedRoute, Router } from '@angular/router';
import { NavbarComponent } from '../../components/navbar/navbar.component';
import { Movie, MovieService } from '../../services/movie.service';
import { ReviewService } from '../../services/review.service';

@Component({
  selector: 'app-create-review',
  standalone: true,
  imports: [CommonModule, ReactiveFormsModule, NavbarComponent],
  templateUrl: './create-review.component.html',
  styleUrl: './create-review.component.css'
})
export class CreateReviewComponent implements OnInit {
  form: FormGroup;
  movies: Movie[] = [];
  loading = true;
  submitting = false;
  error: string | null = null;
  submitted = false;

  constructor(
    private formBuilder: FormBuilder,
    private movieService: MovieService,
    private reviewService: ReviewService,
    private route: ActivatedRoute,
    private router: Router
  ) {
    this.form = this.formBuilder.group({
      movieId: ['', Validators.required],
      rating: [5, [Validators.required, Validators.min(1), Validators.max(10)]],
      content: ['', [Validators.required, Validators.minLength(10)]],
      visibility: [0, Validators.required]
    });
  }

  get f() {
    return this.form.controls;
  }

  ngOnInit() {
    this.movieService.getMovies().subscribe({
      next: (movies) => {
        this.movies = movies;
        this.loading = false;

        const movieId = this.route.snapshot.queryParamMap.get('movieId');
        if (movieId) {
          this.form.patchValue({ movieId: +movieId });
        }
      },
      error: () => {
        this.error = 'Failed to load movies';
        this.loading = false;
      }
    });
  }

  onSubmit() {
    this.submitted = true;
    if (this.form.invalid) return;

    this.submitting = true;
    this.error = null;

    this.reviewService.createReview({
      movieId: +this.form.value.movieId,
      rating: +this.form.value.rating,
      content: this.form.value.content,
      visibility: +this.form.value.visibility
    }).subscribe({
      next: () => {
        this.router.navigate(['/my-reviews']);
      },
      error: (err) => {
        this.error = err.error?.message || 'Failed to create review';
        this.submitting = false;
      }
    });
  }

  goBack() {
    this.router.navigate(['/feed']);
  }
}
<div class="page-container">
  <app-navbar></app-navbar>

  <div class="page-content">
    <button class="back-btn" (click)="goBack()">← Back</button>
    <h1>Write a Review</h1>

    <div *ngIf="loading" class="loading">Loading movies...</div>

    <form *ngIf="!loading" [formGroup]="form" (ngSubmit)="onSubmit()" class="review-form">
      <div class="form-group">
        <label>Movie</label>
        <select formControlName="movieId" class="form-control"
          [class.is-invalid]="submitted && f['movieId'].errors">
          <option value="">Select a movie...</option>
          <option *ngFor="let movie of movies" [value]="movie.id">{{ movie.title }}</option>
        </select>
        <div *ngIf="submitted && f['movieId'].errors" class="error-message">Please select a movie</div>
      </div>

      <div class="form-group">
        <label>Rating (1-10)</label>
        <input type="number" formControlName="rating" min="1" max="10" class="form-control"
          [class.is-invalid]="submitted && f['rating'].errors" />
        <div *ngIf="submitted && f['rating'].errors" class="error-message">Rating must be between 1 and 10</div>
      </div>

      <div class="form-group">
        <label>Review</label>
        <textarea formControlName="content" rows="5" class="form-control"
          placeholder="Share your thoughts (min 10 characters)..."
          [class.is-invalid]="submitted && f['content'].errors"></textarea>
        <div *ngIf="submitted && f['content'].errors" class="error-message">
          Review must be at least 10 characters
        </div>
      </div>

      <div class="form-group">
        <label>Visibility</label>
        <select formControlName="visibility" class="form-control">
          <option [value]="0">Public</option>
          <option [value]="1">Friends Only</option>
        </select>
      </div>

      <div *ngIf="error" class="alert alert-danger">{{ error }}</div>

      <button type="submit" class="btn btn-primary" [disabled]="submitting">
        {{ submitting ? 'Publishing...' : 'Publish Review' }}
      </button>
    </form>
  </div>
</div>
